// Get stored configuration
const khojToken = $env.KHOJ_TOKEN || '';
const hostURL = $env.KHOJ_HOST_URL || 'https://app.khoj.dev';
const filesToSync = $env.FILES_TO_SYNC ? JSON.parse($env.FILES_TO_SYNC) : [];
const foldersToSync = $env.FOLDERS_TO_SYNC ? JSON.parse($env.FOLDERS_TO_SYNC) : [];

if (!khojToken || khojToken === '') {
  return { error: 'Khoj token not configured', syncing: false };
}

if (!hostURL || hostURL === '') {
  return { error: 'Khoj host URL not configured', syncing: false };
}

return {
  khojToken,
  hostURL,
  filesToSync,
  foldersToSync,
  ready: true
};

const fs = require('fs');
const path = require('path');

const validFileTypes = [
  'org', 'md', 'markdown', 'txt', 'html', 'xml',
  'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go',
  'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp',
  'makefile', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python',
  'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql',
  'svg', 'symlinktext', 'vba', 'winregistry', 'yaml',
  'pdf', 'jpg', 'jpeg', 'png', 'webp'
];

function isSupportedFileType(filePath) {
  const ext = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(ext);
}

function processDirectory(folderPath, results = []) {
  try {
    const files = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const fullPath = path.join(folderPath, file.name);
      if (file.isFile() && isSupportedFileType(fullPath)) {
        results.push(fullPath);
      } else if (file.isDirectory()) {
        processDirectory(fullPath, results);
      }
    }
  } catch (err) {
    console.error(`Error reading ${folderPath}: ${err.message}`);
  }
  return results;
}

const filesToSync = $input.all()[0].json.filesToSync || [];
const foldersToSync = $input.all()[0].json.foldersToSync || [];
const filesToPush = [];

// Add individual files
for (const file of filesToSync) {
  if (fs.existsSync(file.path)) {
    filesToPush.push(file.path);
  }
}

// Add files from folders
for (const folder of foldersToSync) {
  if (fs.existsSync(folder.path)) {
    processDirectory(folder.path, filesToPush);
  }
}

return { filesToPush };

const fs = require('fs');

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];

function filenameToMimeType(filename) {
  const ext = filename.split('.').pop().toLowerCase();
  const mimeMap = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'markdown': 'text/markdown',
    'org': 'text/org'
  };
  return mimeMap[ext] || 'text/plain';
}

const filesToPush = $input.all()[0].json.filesToPush || [];
const filesData = [];
const lastSync = $env.LAST_SYNC ? JSON.parse($env.LAST_SYNC) : [];
const regenerate = $input.all()[1]?.json?.regenerate || false;

for (const filePath of filesToPush) {
  const stats = fs.statSync(filePath);

  if (!regenerate) {
    const lastSyncedFile = lastSync.find(f => f.path === filePath);
    if (lastSyncedFile && stats.mtime.toISOString() < lastSyncedFile.datetime) {
      continue;
    }
  }

  try {
    const ext = filePath.split('.').pop().toLowerCase();
    const encoding = binaryFileTypes.includes(ext) ? 'binary' : 'utf8';
    const mimeType = filenameToMimeType(filePath) + (encoding === 'utf8' ? '; charset=UTF-8' : '');
    const fileContent = fs.readFileSync(filePath, { encoding });

    filesData.push({
      path: filePath,
      mimeType: mimeType,
      content: fileContent,
      encoding: encoding
    });
  } catch (err) {
    console.error(`Error reading file ${filePath}: ${err.message}`);
  }
}

return { filesData };

// Handle successful sync response
const response = $input.all()[0].json.body;
const filesData = $input.all()[1].json.filesData || [];

const syncedFiles = filesData.map(file => ({
  path: file.path,
  datetime: new Date().toISOString()
}));

return {
  success: true,
  syncedFiles: syncedFiles,
  lastSync: new Date().toISOString()
};

const error = $input.all()[0].json.error;
const errorMessage = error?.message || 'Unknown sync error';

return {
  success: false,
  error: errorMessage,
  timestamp: new Date().toISOString()
};
